class Solution:
    def maxArea(self, h, w, horizontalCuts, verticalCuts):
        MOD = 10**9 + 7
        def max_gap(cuts, total):
            s = sorted(cuts)
            gaps = [s[0]] + [s[i+1]-s[i] for i in range(len(s)-1)] + [total - s[-1]]
            return max(gaps)
        return (max_gap(horizontalCuts, h) * max_gap(verticalCuts, w)) % MOD

